/* HealingMart Calculator Single Page App v1.5.0
 * Production UI lives on Blogger (healing-mart.com).
 * GitHub Pages provides static JS/CSS/calculator modules only.
 * Original work by Healing Mart.
 */
(function (w, d) {
  "use strict";

  var script = d.currentScript;
  var explicitBase = script && script.dataset ? (script.dataset.base || "") : "";
  var src = script && script.src ? script.src : "";
  var base = (explicitBase || src.replace(/\/dist\/js\/hm-calc-app[^/]*\.js(?:\?.*)?$/, "")).replace(/\/$/, "");
  var dist = base + "/dist";
  var loadedScripts = Object.create(null);
  var originalTitle = d.title;
  var originalDescription = (d.querySelector('meta[name="description"]') || {}).content || "";

  function esc(value) {
    return String(value == null ? "" : value).replace(/[&<>"']/g, function (ch) {
      return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[ch];
    });
  }

  function icon(id) {
    var paths = {
      life: '<path d="M5 4h14v16H5z"></path><path d="M8 8h8M8 12h3M13 12h3M8 16h3M13 16h3"></path>',
      finance: '<path d="M4 9h16M6 9V6l6-3 6 3v3M6 9v9M10 9v9M14 9v9M18 9v9M4 18h16v3H4z"></path>',
      health: '<path d="M12 21s-7-4.35-7-10a4 4 0 0 1 7-2.65A4 4 0 0 1 19 11c0 5.65-7 10-7 10z"></path><path d="M8.5 13h2l1-3 1.5 5 1-2h2"></path>',
      date: '<rect x="4" y="5" width="16" height="15" rx="2"></rect><path d="M8 3v4M16 3v4M4 9h16M8 13h2M12 13h2M16 13h1"></path>',
      unit: '<path d="M4 7h16v10H4z"></path><path d="M7 7v4M10 7v2M13 7v4M16 7v2"></path>',
      math: '<path d="M5 6h6M8 3v6M14 5l5 5M19 5l-5 5M5 15h6M14 16h5"></path><circle cx="16.5" cy="13.5" r=".6"></circle><circle cx="16.5" cy="18.5" r=".6"></circle>',
      "payroll-tax": '<path d="M6 3h12v18l-3-2-3 2-3-2-3 2V3z"></path><path d="M9 8h6M9 12h6M9 16h3"></path>',
      "real-estate": '<path d="M3 11l9-8 9 8"></path><path d="M5 10v10h14V10M9 20v-6h6v6"></path>',
      auto: '<path d="M5 16h14l-1-6-2-3H8L6 10l-1 6z"></path><path d="M4 16v3h3v-2h10v2h3v-3M7 13h2M15 13h2"></path>',
      education: '<path d="M4 5h7a3 3 0 0 1 3 3v11a3 3 0 0 0-3-3H4V5z"></path><path d="M20 5h-3a3 3 0 0 0-3 3v11a3 3 0 0 1 3-3h3V5z"></path>',
      food: '<path d="M7 3v8M4 3v5a3 3 0 0 0 6 0V3M7 11v10M16 3v18M16 3c3 2 4 5 4 8h-4"></path>',
      science: '<path d="M9 3h6M10 3v6l-5 9a2 2 0 0 0 2 3h10a2 2 0 0 0 2-3l-5-9V3"></path><path d="M8 15h8"></path>'
    };
    return '<svg viewBox="0 0 24 24" aria-hidden="true">' + (paths[id] || paths.life) + '</svg>';
  }

  function normalizeText(text) {
    return String(text == null ? "" : text)
      .replace(/(?:&amp;)?#39;?/g, "'")
      .replace(/(?:&amp;)?#183;?/g, "·")
      .replace(/(?:&amp;)?#215;?/g, "×")
      .replace(/(?:&amp;)?#8230;?/g, "…")
      .replace(/(?:&amp;)?#572;?/g, "");
  }

  function cleanTextNodes(root) {
    if (!root || !d.createTreeWalker) return;
    var walker = d.createTreeWalker(root, NodeFilter.SHOW_TEXT, null);
    var node;
    while ((node = walker.nextNode())) {
      var next = normalizeText(node.nodeValue);
      if (next !== node.nodeValue) node.nodeValue = next;
    }
  }

  function loadScript(url, attrs) {
    if (loadedScripts[url]) return loadedScripts[url];
    loadedScripts[url] = new Promise(function (resolve, reject) {
      var s = d.createElement("script");
      s.src = url;
      if (attrs) Object.keys(attrs).forEach(function (key) { s.setAttribute(key, attrs[key]); });
      s.onload = function () { resolve(s); };
      s.onerror = function () { reject(new Error("로드 실패: " + url)); };
      d.head.appendChild(s);
    });
    return loadedScripts[url];
  }

  function ensureCss() {
    if (d.getElementById("hm-calc-css-v1")) return;
    var link = d.createElement("link");
    link.id = "hm-calc-css-v1";
    link.rel = "stylesheet";
    link.href = dist + "/css/hm-calc.v1.css";
    d.head.appendChild(link);
  }

  async function ensureRegistry() {
    if (w.HM_CALC_INDEX) return w.HM_CALC_INDEX;
    await loadScript(dist + "/data/hm-calc-registry.v1.js");
    return w.HM_CALC_INDEX;
  }

  function getData() {
    var data = w.HM_CALC_INDEX || {categories:[], calculators:[]};
    var categories = (data.categories || []).filter(function (c) { return c.enabled !== false; }).sort(function (a,b) { return (a.order || 0) - (b.order || 0); });
    var calculators = (data.calculators || []).filter(function (c) { return c.enabled !== false && c.published === true; });
    return {version:data.version || "1", categories:categories, calculators:calculators};
  }

  function belongs(calc, categoryId) {
    var list = Array.isArray(calc.categories) ? calc.categories : [calc.category || calc.primaryCategory];
    return list.indexOf(categoryId) !== -1;
  }

  function categoryCalcs(calculators, categoryId) {
    return calculators.filter(function (calc) { return belongs(calc, categoryId); });
  }

  function isCategoryAvailable(category, calculators) {
    return !!category && category.status === "active" && categoryCalcs(calculators, category.id).length > 0;
  }

  function routeUrl(params) {
    var url = new URL(w.location.href);
    url.searchParams.delete("category");
    url.searchParams.delete("calc");
    if (params && params.category) url.searchParams.set("category", params.category);
    if (params && params.calc) url.searchParams.set("calc", params.calc);
    url.hash = "";
    return url.pathname + (url.search ? url.search : "");
  }

  function routeHref(params) {
    var url = new URL(w.location.href);
    url.searchParams.delete("category");
    url.searchParams.delete("calc");
    if (params && params.category) url.searchParams.set("category", params.category);
    if (params && params.calc) url.searchParams.set("calc", params.calc);
    url.hash = "";
    return url.href;
  }

  function currentRoute() {
    var params = new URLSearchParams(w.location.search);
    return { category: params.get("category") || "", calc: params.get("calc") || "" };
  }

  function setDocumentMeta(title, description) {
    d.title = title || originalTitle;
    var meta = d.querySelector('meta[name="description"]');
    if (meta && description) meta.content = description;
    else if (meta && originalDescription) meta.content = originalDescription;
  }

  function navHtml(categories, calculators, selectedId) {
    return '<nav class="hm-category-pills hm-calc-app-pills" aria-label="계산기 카테고리">' +
      '<a class="hm-category-pill is-all' + (!selectedId ? ' is-active' : '') + '" href="' + esc(routeHref({})) + '" data-hm-route="home">전체</a>' +
      categories.map(function (cat) {
        var available = isCategoryAvailable(cat, calculators);
        if (!available) {
          return '<span class="hm-category-pill is-' + esc(cat.id) + ' is-coming" aria-disabled="true" title="준비 중">' + icon(cat.id) + '<span>' + esc(cat.name) + '</span></span>';
        }
        return '<a class="hm-category-pill is-' + esc(cat.id) + (cat.id === selectedId ? ' is-active' : '') + '" href="' + esc(routeHref({category:cat.id})) + '" data-hm-route="category" data-category-id="' + esc(cat.id) + '">' + icon(cat.id) + '<span>' + esc(cat.name) + '</span></a>';
      }).join('') + '</nav>';
  }

  function noticeHtml() {
    return '<aside class="hm-directory-notice hm-calc-app-notice">' +
      '<span class="hm-directory-notice-dot" aria-hidden="true"></span>' +
      '<div><strong>계산기는 계속 추가되고 있습니다.</strong><p>필요한 계산기 제안이나 계산 오류는 힐링편의점 오류·문의 페이지에 알려주세요.</p></div>' +
      '<a href="https://www.healing-mart.com/p/qna.html">오류·문의 →</a>' +
      '</aside>';
  }

  function renderHub(stage, data) {
    setDocumentMeta(originalTitle, originalDescription);
    stage.innerHTML =
      '<section class="hm-directory-head hm-calc-app-head">' +
        '<div><span class="hm-directory-kicker">HEALING MART CALCULATOR</span><h1>계산기 카테고리</h1><p class="hm-directory-sub">필요한 계산을 카테고리에서 골라보세요.</p></div>' +
      '</section>' +
      '<section class="hm-category-board hm-calc-app-category-board" aria-label="계산기 카테고리">' +
      data.categories.map(function (cat) {
        var count = categoryCalcs(data.calculators, cat.id).length;
        var available = isCategoryAvailable(cat, data.calculators);
        if (available) {
          return '<a class="hm-category-card is-' + esc(cat.id) + ' is-available" href="' + esc(routeHref({category:cat.id})) + '" data-hm-route="category" data-category-id="' + esc(cat.id) + '">' +
            '<span class="hm-category-icon">' + icon(cat.id) + '</span>' +
            '<strong>' + esc(cat.name) + '</strong>' +
            '<span class="hm-category-description">' + esc(cat.description || '') + '</span>' +
            '<span class="hm-category-count">' + count + '개 계산기 <b aria-hidden="true">→</b></span>' +
          '</a>';
        }
        return '<div class="hm-category-card is-' + esc(cat.id) + ' is-coming" aria-disabled="true">' +
          '<span class="hm-category-icon">' + icon(cat.id) + '</span>' +
          '<strong>' + esc(cat.name) + '</strong>' +
          '<span class="hm-category-description">' + esc(cat.description || '') + '</span>' +
          '<span class="hm-category-count">준비 중</span>' +
        '</div>';
      }).join('') + '</section>' + noticeHtml();
    cleanTextNodes(stage);
  }

  function renderCategory(stage, data, categoryId) {
    var cat = data.categories.find(function (item) { return item.id === categoryId; });
    if (!cat || !isCategoryAvailable(cat, data.calculators)) {
      renderHub(stage, data);
      return;
    }
    var calcs = categoryCalcs(data.calculators, cat.id);
    setDocumentMeta(cat.name + ' 계산기 | 힐링편의점', cat.description || originalDescription);
    stage.innerHTML =
      '<div class="hm-directory-category-view hm-calc-app-category-view">' +
        '<div class="hm-calc-app-topline"><a class="hm-directory-back" href="' + esc(routeHref({})) + '" data-hm-route="home">← 전체 카테고리</a></div>' +
        navHtml(data.categories, data.calculators, cat.id) +
        '<section class="hm-category-hero is-' + esc(cat.id) + '">' +
          '<span class="hm-category-hero-icon">' + icon(cat.id) + '</span>' +
          '<div><span class="hm-category-overline">HEALING MART · ' + esc(cat.name) + '</span><h1>' + esc(cat.name) + ' 계산기</h1><p>' + esc(cat.description || '') + '</p></div>' +
        '</section>' +
        '<section class="hm-category-list">' +
          '<div class="hm-category-list-head"><h2>이용 가능한 계산기</h2>' +
            (calcs.length >= 8 ? '<label class="hm-category-search"><span>검색</span><input type="search" placeholder="' + esc(cat.name) + ' 계산기 검색" autocomplete="off"></label>' : '') +
          '</div>' +
          '<div class="hm-category-calculator-grid">' + calcs.map(function (calc) {
            var searchable = [calc.name, calc.description].concat(calc.keywords || []).join(' ').toLowerCase();
            return '<a class="hm-category-calculator-card is-' + esc(cat.id) + '" href="' + esc(routeHref({category:cat.id, calc:calc.id})) + '" data-hm-route="calculator" data-category-id="' + esc(cat.id) + '" data-calculator-id="' + esc(calc.id) + '" data-search="' + esc(searchable) + '">' +
              '<span class="hm-category-calculator-icon">' + icon(cat.id) + '</span>' +
              '<span class="hm-category-calculator-copy"><strong>' + esc(calc.name) + '</strong><small>' + esc(calc.description || '') + '</small></span>' +
              '<span class="hm-category-calculator-arrow">→</span>' +
            '</a>';
          }).join('') + '</div>' +
          '<div class="hm-calc-empty" hidden><strong>검색 결과가 없습니다.</strong><span>다른 검색어를 입력해 보세요.</span></div>' +
        '</section>' + noticeHtml() +
      '</div>';
    cleanTextNodes(stage);

    var input = stage.querySelector('.hm-category-search input');
    if (input) input.addEventListener('input', function () {
      var q = input.value.trim().toLowerCase();
      var cards = Array.prototype.slice.call(stage.querySelectorAll('.hm-category-calculator-card'));
      var shown = 0;
      cards.forEach(function (card) {
        var visible = !q || (card.getAttribute('data-search') || '').indexOf(q) !== -1;
        card.hidden = !visible;
        if (visible) shown += 1;
      });
      var empty = stage.querySelector('.hm-calc-empty');
      if (empty) empty.hidden = shown > 0;
    });
  }

  function contentHtml(calc) {
    var content = calc.content || {};
    var useCases = (content.useCases || []).map(function (v) { return '<li>' + esc(v) + '</li>'; }).join('');
    var notes = (content.notes || []).map(function (v) { return '<li>' + esc(v) + '</li>'; }).join('');
    var faq = (content.faq || []).map(function (v) { return '<details class="hm-seo-faq"><summary>' + esc(v.q) + '</summary><p>' + esc(v.a) + '</p></details>'; }).join('');
    var sections = '';
    if (useCases) sections += '<section><h2>이럴 때 사용해요</h2><ul>' + useCases + '</ul></section>';
    if (content.howItWorks) sections += '<section><h2>어떻게 계산하나요?</h2><p>' + esc(content.howItWorks) + '</p></section>';
    if (content.example) sections += '<section><h2>사용 예시</h2><p>' + esc(content.example) + '</p></section>';
    if (notes) sections += '<section><h2>알아두세요</h2><ul>' + notes + '</ul></section>';
    if (faq) sections += '<section><h2>자주 묻는 질문</h2>' + faq + '</section>';
    return sections ? '<article class="hm-seo-guide">' + sections + '</article>' : '';
  }

  async function ensureCalculatorBase() {
    if (!w.HM_CALC || !w.HM_CALC.mount) await loadScript(dist + '/js/hm-calc-core.v1.min.js');
    if (!w.HM_CALC_SOUND) await loadScript(dist + '/js/hm-calc-sound.v1.min.js');
    if (!w.HM_CALC_SHARE) await loadScript(dist + '/js/hm-calc-share.v1.min.js');
  }

  async function mountCalculator(widget, calc) {
    try {
      await ensureCalculatorBase();
      if (!w.HM_CALC.has(calc.id)) await loadScript(dist + '/calculators/' + encodeURIComponent(calc.module || calc.id) + '.min.js');
      w.HM_CALC.mount(widget, calc.id);
      if (w.HM_CALC_SOUND && w.HM_CALC_SOUND.mount) w.HM_CALC_SOUND.mount(widget);
      if (w.HM_CALC_SHARE && w.HM_CALC_SHARE.mount) w.HM_CALC_SHARE.mount(widget);
    } catch (err) {
      widget.innerHTML = '<div class="hm-calc-error">계산기를 불러오지 못했습니다. 잠시 후 다시 시도해 주세요.</div>';
      console.error(err);
    }
  }

  async function renderCalculator(stage, data, calcId, categoryId) {
    var calc = data.calculators.find(function (item) { return item.id === calcId; });
    if (!calc) {
      renderHub(stage, data);
      return;
    }
    var cat = data.categories.find(function (item) { return item.id === categoryId && belongs(calc, item.id) && isCategoryAvailable(item, data.calculators); });
    if (!cat) cat = data.categories.find(function (item) { return item.id === (calc.primaryCategory || calc.category || 'life'); });
    if (!cat || !isCategoryAvailable(cat, data.calculators)) cat = data.categories.find(function (item) { return item.id === 'life'; }) || data.categories[0];

    var related = categoryCalcs(data.calculators, cat.id).filter(function (item) { return item.id !== calc.id; }).slice(0, 4);
    setDocumentMeta(calc.name + ' | 힐링편의점', calc.description || originalDescription);

    stage.innerHTML =
      '<div class="hm-calc-app-detail is-' + esc(cat.id) + '">' +
        '<div class="hm-calc-app-topline"><a class="hm-directory-back" href="' + esc(routeHref({category:cat.id})) + '" data-hm-route="category" data-category-id="' + esc(cat.id) + '">← ' + esc(cat.name) + ' 계산기</a><a class="hm-calc-app-home-link" href="' + esc(routeHref({})) + '" data-hm-route="home">전체 카테고리</a></div>' +
        navHtml(data.categories, data.calculators, cat.id) +
        '<div class="hm-detail-main hm-calc-app-detail-main">' +
          '<header class="hm-detail-heading">' +
            '<div class="hm-detail-breadcrumb"><a href="' + esc(routeHref({})) + '" data-hm-route="home">계산기</a><span>›</span><a href="' + esc(routeHref({category:cat.id})) + '" data-hm-route="category" data-category-id="' + esc(cat.id) + '">' + esc(cat.name) + '</a></div>' +
            '<span class="hm-detail-category-badge is-' + esc(cat.id) + '">' + icon(cat.id) + esc(cat.name) + '</span>' +
            '<h1 class="hm-detail-title">' + esc(calc.name) + '</h1>' +
            '<p class="hm-detail-desc">' + esc(calc.description || '') + '</p>' +
          '</header>' +
          '<div class="hm-calc-app-widget-wrap"><div data-hm-calculator="' + esc(calc.id) + '"></div></div>' +
          contentHtml(calc) +
          (related.length ? '<section class="hm-detail-related"><div class="hm-detail-related-head"><h2>같은 카테고리 계산기</h2><a href="' + esc(routeHref({category:cat.id})) + '" data-hm-route="category" data-category-id="' + esc(cat.id) + '">' + esc(cat.name) + ' 전체보기 →</a></div><div class="hm-related-grid">' + related.map(function (item) {
            return '<a class="hm-related-card" href="' + esc(routeHref({category:cat.id, calc:item.id})) + '" data-hm-route="calculator" data-category-id="' + esc(cat.id) + '" data-calculator-id="' + esc(item.id) + '">' + esc(item.name) + '<span>→</span></a>';
          }).join('') + '</div></section>' : '') +
          noticeHtml() +
        '</div>' +
      '</div>';
    cleanTextNodes(stage);
    var widget = stage.querySelector('[data-hm-calculator]');
    if (widget) await mountCalculator(widget, calc);
  }

  function validateRoute(route, data) {
    if (route.calc) {
      var calc = data.calculators.find(function (item) { return item.id === route.calc; });
      if (calc) {
        var catId = route.category;
        var cat = data.categories.find(function (item) { return item.id === catId && belongs(calc, item.id) && isCategoryAvailable(item, data.calculators); });
        if (!cat) cat = data.categories.find(function (item) { return item.id === (calc.primaryCategory || calc.category || 'life') && isCategoryAvailable(item, data.calculators); });
        if (cat) return {view:'calculator', category:cat.id, calc:calc.id};
      }
    }
    if (route.category) {
      var category = data.categories.find(function (item) { return item.id === route.category; });
      if (isCategoryAvailable(category, data.calculators)) return {view:'category', category:category.id};
    }
    return {view:'home'};
  }

  function scrollAppTop(root) {
    if (!root) return;
    var top = root.getBoundingClientRect().top + w.pageYOffset - 12;
    if (Math.abs(w.pageYOffset - top) > 80) w.scrollTo({top:Math.max(0, top), behavior:'smooth'});
  }

  async function renderApp(root, options) {
    options = options || {};
    var stage = root.querySelector('[data-hm-calc-stage]') || root;
    var data = getData();
    var route = validateRoute(currentRoute(), data);
    root.dataset.hmCalcView = route.view;
    if (route.view === 'calculator') await renderCalculator(stage, data, route.calc, route.category);
    else if (route.view === 'category') renderCategory(stage, data, route.category);
    else renderHub(stage, data);
    if (options.scroll !== false) scrollAppTop(root);
  }

  function bindRouting(root) {
    if (root.dataset.hmCalcRoutingBound === 'true') return;
    root.dataset.hmCalcRoutingBound = 'true';
    root.addEventListener('click', function (event) {
      var target = event.target.closest('[data-hm-route]');
      if (!target || event.defaultPrevented || event.metaKey || event.ctrlKey || event.shiftKey || event.altKey) return;
      event.preventDefault();
      var action = target.getAttribute('data-hm-route');
      var next = {};
      if (action === 'category') next.category = target.getAttribute('data-category-id') || '';
      if (action === 'calculator') {
        next.category = target.getAttribute('data-category-id') || '';
        next.calc = target.getAttribute('data-calculator-id') || '';
      }
      w.history.pushState({hmCalc:true}, '', routeUrl(next));
      renderApp(root, {scroll:true});
    });
  }

  async function bootRoot(root) {
    if (root.dataset.hmCalcAppMounted === 'true') return;
    root.dataset.hmCalcAppMounted = 'true';
    ensureCss();
    var stage = root.querySelector('[data-hm-calc-stage]') || root;
    stage.innerHTML = '<div class="hm-calc-app-loading" role="status">계산기를 불러오는 중입니다.</div>';
    try {
      await ensureRegistry();
      bindRouting(root);
      await renderApp(root, {scroll:false});
    } catch (err) {
      stage.innerHTML = '<div class="hm-invalid"><h2>계산기 데이터를 불러오지 못했습니다.</h2><p>잠시 후 새로고침해 주세요.</p></div>';
      console.error(err);
    }
  }

  async function boot() {
    var roots = Array.prototype.slice.call(d.querySelectorAll('[data-hm-calc-app]'));
    for (var i = 0; i < roots.length; i += 1) await bootRoot(roots[i]);
  }

  w.addEventListener('popstate', function () {
    var root = d.querySelector('[data-hm-calc-app]');
    if (root && w.HM_CALC_INDEX) renderApp(root, {scroll:false});
  });

  w.HM_CALC_APP = { render:renderApp, routeHref:routeHref };

  try {
    console.info('%cHealing Mart%c Calculator App v1.5.0', 'color:#0b7fd7;font-size:14px;font-weight:800;', 'color:#20202a;font-weight:700;');
  } catch (_) {}

  if (d.readyState === 'loading') d.addEventListener('DOMContentLoaded', boot, {once:true});
  else boot();
})(window, document);
